div.script:
function previewImage(input) {
    if (input.files && input.files[0]) {
        var reader = new FileReader();

        document.getElementById('upload_prompt').classList.add('tw-hidden');
        document.getElementById('image_preview_container').classList.add('tw-hidden');
        document.getElementById('loading_state').classList.remove('tw-hidden');

        reader.onload = function(e) {
            setTimeout(function() {
                document.getElementById('loading_state').classList.add('tw-hidden');
                document.getElementById('image_preview_container').classList.remove('tw-hidden');
                document.getElementById('image_preview').src = e.target.result;
            }, 800);
        }

        reader.readAsDataURL(input.files[0]);
    }
}

/* ===== AJAX Form Submit ===== */
document.addEventListener('DOMContentLoaded', function() {
    var form = document.getElementById('ktm_form');
    if (!form) return;

    form.addEventListener('submit', function(e) {
        e.preventDefault();

        var fileInput = document.getElementById('ktm_file');
        if (!fileInput.files || !fileInput.files[0]) {
            showPopup('error', 'Oops!', 'Pilih file KTM terlebih dahulu.');
            return;
        }

        // Show loading state on button
        var btnText = document.getElementById('btn_text');
        var btnSpinner = document.getElementById('btn_spinner');
        var btnSubmit = document.getElementById('btn_submit');
        btnText.textContent = 'MEMPROSES...';
        btnSpinner.classList.remove('tw-hidden');
        btnSubmit.disabled = true;
        btnSubmit.classList.add('tw-opacity-70');

        var formData = new FormData(form);

        fetch('/seller-verification/submit', {
            method: 'POST',
            body: formData,
        })
        .then(function(response) { return response.json(); })
        .then(function(data) {
            // Reset button
            btnText.textContent = 'MASUKAN';
            btnSpinner.classList.add('tw-hidden');
            btnSubmit.disabled = false;
            btnSubmit.classList.remove('tw-opacity-70');

            if (data.status === 'approved') {
                showPopup('success', 'Verifikasi Berhasil ✅', data.message || 'KTM Anda telah diverifikasi.');
            } else if (data.status === 'rejected') {
                showPopup('rejected', 'Pengajuan Ditolak ❌', data.message || 'Pastikan Anda mahasiswa UNISA.');
            } else if (data.status === 'invalid_image') {
                showPopup('warning', 'Gambar Tidak Sesuai', data.message || 'Coba lagi dengan foto KTM yang benar.');
            } else if (data.status === 'no_name') {
                showPopup('warning', 'Foto Tidak Valid', data.message || 'Pastikan upload foto KTM');
            } else {
                showPopup('error', 'Terjadi Kesalahan', data.message || 'Silakan coba lagi.');
            }
        })
        .catch(function(err) {
            btnText.textContent = 'MASUKAN';
            btnSpinner.classList.add('tw-hidden');
            btnSubmit.disabled = false;
            btnSubmit.classList.remove('tw-opacity-70');
            showPopup('error', 'Koneksi Gagal', 'Tidak dapat menghubungi server. Periksa koneksi Anda.');
        });
    });
});

/* ===== Popup Functions ===== */
function showPopup(type, title, message) {
    var popup = document.getElementById('result_popup');
    var iconEl = document.getElementById('popup_icon');
    var titleEl = document.getElementById('popup_title');
    var msgEl = document.getElementById('popup_message');

    titleEl.textContent = title;
    msgEl.textContent = message;

    // Set icon + color based on type
    if (type === 'success') {
        iconEl.className = 'tw-w-[72px] tw-h-[72px] tw-rounded-full tw-flex tw-items-center tw-justify-center tw-mb-5 tw-bg-green-100';
        iconEl.innerHTML = '';
    } else if (type === 'rejected') {
        iconEl.className = 'tw-w-[72px] tw-h-[72px] tw-rounded-full tw-flex tw-items-center tw-justify-center tw-mb-5 tw-bg-red-100';
        iconEl.innerHTML = '';
    } else if (type === 'warning') {
        iconEl.className = 'tw-w-[72px] tw-h-[72px] tw-rounded-full tw-flex tw-items-center tw-justify-center tw-mb-5 tw-bg-yellow-100';
        iconEl.innerHTML = '';
    } else {
        iconEl.className = 'tw-w-[72px] tw-h-[72px] tw-rounded-full tw-flex tw-items-center tw-justify-center tw-mb-5 tw-bg-gray-100';
        iconEl.innerHTML = '';
    }

    popup.classList.remove('tw-hidden');
}

function closePopup() {
    document.getElementById('result_popup').classList.add('tw-hidden');
    // Reload page to refresh status banner
    window.location.reload();
}
